UPDATE vehicle
plate_number = #{plateNumber}, vehicle_type = #{vehicleType}, brand = #{brand}, model = #{model}, color = #{color}, load_capacity = #{loadCapacity}, status = #{status}, device_id = #{deviceId}, driver_id = #{driverId}, driver_name = #{driverName}, current_longitude = #{currentLongitude}, current_latitude = #{currentLatitude}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT v.id, v.plate_number, v.vehicle_type, v.brand, v.model, v.color, v.load_capacity, v.status, v.device_id, v.driver_id, d.name as driver_name, v.current_longitude, v.current_latitude, v.last_update_time, v.create_time, v.update_time, v.speed FROM vehicle v LEFT JOIN driver d ON v.driver_id = d.id
AND v.status = #{status}
AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND v.vehicle_type = #{vehicleType}
ORDER BY v.create_time DESC

SELECT COUNT(*) FROM vehicle

    
        AND status = #{status}
    
    
        AND plate_number LIKE CONCAT('%', #{plateNumber}, '%')
    
    
        AND vehicle_type = #{vehicleType}
